&= 19 \left(x - \left\lfloor \frac{x}{19} \right\rfloor(19) \right) - \left\lfloor x \right\rfloor\\
&\le 19\left(x - 19\left\lfloor\frac{x}{19}\right\rfloor\right)
\end{aligned}
\text{and}
